    apiKey: 'sk_live_abcdef123456789',
    dbPassword: 'MySecretPassword123!',
    jwtSecret: 'super-secret-key-do-not-share'
};

// SECURE: Use environment variables and configuration validation
class SecureConfiguration {
    constructor() {
        this.config = this.loadConfiguration();
    }

    loadConfiguration() {
        // Validate required environment variables
        const required = ['API_KEY', 'DB_HOST', 'JWT_SECRET'];
        const missing = required.filter(key => !process.env[key]);

        if (missing.length > 0) {
            throw new Error(
                `Missing required environment variables: ${missing.join(', ')}`
            );
        }

        // Validate sensitive data never appears in config object
        const sensitivePatterns = [
            /sk_live_|pk_live_/,  // Stripe-like keys
            /password|passwd/i,
            /secret|token/i,
            /-----BEGIN.*PRIVATE KEY-----/
        ];

        // Check for any hardcoded sensitive values
        const envValues = Object.values(process.env);
        for (const pattern of sensitivePatterns) {
            for (const value of envValues) {
                if (typeof value === 'string' && pattern.test(value)) {
                    console.warn('Warning: Sensitive pattern detected in environment');
                }
            }
        }

        return {
            apiKey: process.env.API_KEY,
            dbHost: process.env.DB_HOST,
            dbPort: parseInt(process.env.DB_PORT || '5432', 10),
            jwtSecret: process.env.JWT_SECRET,
            // Use derived values, never raw secrets
            jwtAlgorithm: 'HS256'
        };
    }

    // Validate configuration at startup
    validate() {
        if (!this.config.jwtSecret || this.config.jwtSecret.length < 32) {
            throw new Error('JWT secret must be at least 32 characters');
        }

        // Verify JWT secret isn't a known weak value
        const weakSecrets = ['secret', 'password', '123456', 'changeme'];
        if (weakSecrets.includes(this.config.jwtSecret.toLowerCase())) {
            throw new Error('JWT secret is in list of weak/common values');
        }

        return true;
    }
}

// Security scanner for code review checkpoints
function scanForSecrets(code) {
    const secretPatterns = [
        { pattern: /[a-zA-Z0-9_-]{20,}/g, name: 'Potential API key' },
        { pattern: /password\s*=\s*["'][^"']+["']/gi, name: 'Hardcoded password' },
        { pattern: /-----BEGIN.*PRIVATE KEY-----/, name: 'Private key detected' },
        { pattern: /sk_live_[a-zA-Z0-9]{24,}/, name: 'Stripe live key' }
    ];

